export async function POST(req: Request) {
  // Auth — header secret OR any logged-in user
  const headerSecret = req.headers.get('x-migration-secret');
  const expected = process.env.MIGRATION_SECRET;
  let authed = !!(expected && headerSecret === expected);
  if (!authed) {
    const session = await getCurrentUser();
    if (session?.email) authed = true;  // any valid session
  }
  if (!authed) {
    return NextResponse.json(
      { ok: false, error: 'unauthorized' },
      { status: 401 },
    );
  }

  const startedAt = Date.now();
  const chunkResults: Array<{
    chunk: string;
    statements: number;
    ok: boolean;
    error?: string;
    ms: number;
  }> = [];

  for (const {name, sql} of CHUNKS) {
    const chunkStart = Date.now();
    // Feed the whole chunk to pg as a multi-statement simple query. This
    // lets PostgreSQL parse the SQL itself (so semicolons inside single-
    // quoted strings are handled correctly). Each chunk already wraps
    // its own BEGIN/COMMIT.
    const client = await pool.connect();
    let succeeded = 0;
    try {
      await client.query(sql);
      succeeded = 1;
      chunkResults.push({
        chunk: name,
        statements: succeeded,
        ok: true,
        ms: Date.now() - chunkStart,
      });
    } catch (e) {
      try { await client.query('ROLLBACK'); } catch { /* ignore */ }
      chunkResults.push({
        chunk: name,
        statements: succeeded,
        ok: false,
        error: String(e instanceof Error ? e.message : e).slice(0, 800),
        ms: Date.now() - chunkStart,
      });
      return NextResponse.json(
        {
          ok: false,
          error: 'chunk_failed',
          chunkResults,
          total_ms: Date.now() - startedAt,
        },
        { status: 500 },
      );
    } finally {
      client.release();
    }
  }

  const summary = await pool.query<{ k: string; v: string }>(`
    SELECT 'patients_with_comorbidities' AS k, COUNT(DISTINCT patient_id)::text AS v FROM patient_comorbidities
    UNION ALL SELECT 'patients_with_allergies', COUNT(*)::text FROM patients WHERE known_allergies IS NOT NULL AND known_allergies <> ''
    UNION ALL SELECT 'total_completed_encs', COUNT(*)::text FROM encounters WHERE status='completed'
    UNION ALL SELECT 'today_encs_v', COUNT(*)::text FROM encounters
      WHERE encounter_date = CURRENT_DATE AND doctor_id = '2a03f6df-6023-4250-92ad-bd8770196f08'
    UNION ALL SELECT 'avg_history_per_patient',
      ROUND(AVG(c)::numeric, 2)::text FROM
        (SELECT COUNT(*) c FROM encounters WHERE status='completed' GROUP BY patient_id) x
  `);

  return NextResponse.json({
    ok: true,
    chunkResults,
    summary: Object.fromEntries(summary.rows.map(r => [r.k, r.v])),
    total_ms: Date.now() - startedAt,
  });
}

export async function GET(req: Request) { return POST(req); }
